insert into public.tutor_profiles (id, bio, display_name, hourly_rate, trial_rate, rating_avg, review_count, experience, is_approved, is_available) values
('22222222-0000-0000-0000-000000000007', 'מורה לאנגלית ולמדעים. בוגרת אוניברסיטת חיפה. מתמחה בילדים עם קשיי קשב וריכוז.', 'שירה גולן', 115, 55, 4.78, 9, 4, true, true),
('22222222-0000-0000-0000-000000000008', 'מורה להיסטוריה וגיאוגרפיה. מביא את הסיפורים לחיים. שיעורים אינטראקטיביים עם מפות, סרטונים ודיונים.', 'עומר דביר', 100, 50, 4.55, 5, 6, true, true),
('22222222-0000-0000-0000-000000000009', 'מורה למתמטיקה ועברית. 12 שנות ניסיון. סבלנית, יצירתית ומחויבת להצלחת כל תלמיד.', 'תמר ברק', 105, 55, 4.82, 11, 12, true, true),
('22222222-0000-0000-0000-000000000010', 'מורה למדעים. דוקטורנט בביולוגיה. מלמד דרך ניסויים מעשיים וסקרנות טבעית.', 'אייל פרידמן', 135, 65, 4.67, 7, 3, true, true),
('22222222-0000-0000-0000-000000000011', 'מורה לאנגלית עם ניסיון בינלאומי. חיה 5 שנים בניו יורק. שיעורים בשיטת Immersion.', 'מאיה רוזנברג', 125, 60, 4.88, 14, 8, true, true),
('22222222-0000-0000-0000-000000000012', 'מורה למתמטיקה. סטודנט להנדסה. מלמד בגישה טכנולוגית עם אפליקציות ומשחקים.', 'עידו כץ', 90, 45, 4.40, 3, 2, true, true),
('22222222-0000-0000-0000-000000000013', 'מורה לעברית ולאנגלית. מתמחה בדיסלקציה ולקויות למידה. גישה אישית לכל תלמיד.', 'ליאורה סגל', 145, 70, 4.93, 16, 11, true, true),
('22222222-0000-0000-0000-000000000014', 'מורה למתמטיקה ולמדעים. אוהב לפשט את המורכב. שיעורים עם הומור וקלילות.', 'גל עמרני', 100, 50, 4.58, 5, 4, true, true),
('22222222-0000-0000-0000-000000000015', 'מורה להיסטוריה. מאסטר בהיסטוריה של המזרח התיכון. מלמדת דרך סרטים ודוקומנטרים.', 'יעל נחום', 110, 55, 4.70, 7, 5, true, true),
('22222222-0000-0000-0000-000000000016', 'מורה לגיאוגרפיה ומדעים. מדריכת טיולים לשעבר. מביאה את העולם לכיתה.', 'רותם אלון', 95, 45, 4.45, 4, 3, true, true),
('22222222-0000-0000-0000-000000000017', 'מורה למתמטיקה. מנטור לאולימפיאדת מתמטיקה. מתאים לתלמידים מתקדמים שרוצים אתגר.', 'אורי שפירא', 150, 75, 4.97, 19, 9, true, true),
('22222222-0000-0000-0000-000000000018', 'מורה לאנגלית ועברית. בוגרת סמינר הקיבוצים. אוהבת ליצור חומרי לימוד מותאמים אישית.', 'עדן מלכה', 90, 45, 4.35, 3, 2, true, true),
('22222222-0000-0000-0000-000000000019', 'מורה למדעים ולמתמטיקה. 15 שנות ניסיון. מומחה בהכנה למבחנים ובניית ביטחון.', 'ליאור בן עמי', 140, 70, 4.90, 13, 15, true, true),
('22222222-0000-0000-0000-000000000020', 'מורה לעברית. משוררת ומחברת ספרי ילדים. מלמדת כתיבה יצירתית ואהבת הקריאה.', 'הילה דיין', 115, 55, 4.75, 8, 6, true, true),
('22222222-0000-0000-0000-000000000021', 'מורה לאנגלית ולהיסטוריה. דובר 4 שפות. שיעורים רב-תחומיים ומרתקים.', 'איתי מור', 105, 50, 4.60, 6, 4, true, true),
('22222222-0000-0000-0000-000000000022', 'מורה למתמטיקה. מתמחה בשברים, אחוזים ואלגברה. סבלנית ובעלת גישה חיובית.', 'ספיר וולף', 100, 50, 4.52, 5, 3, true, true),
('22222222-0000-0000-0000-000000000023', 'מורה למדעים. חוקר בטכניון. מלמד דרך פרויקטים וחקר מודרך.', 'נועם גרינברג', 130, 65, 4.83, 10, 7, true, true),
('22222222-0000-0000-0000-000000000024', 'מורה לגיאוגרפיה ועברית. אוהבת מפות, תרבויות ושפה. שיעורים צבעוניים ומגוונים.', 'דנה פלג', 95, 45, 4.48, 4, 3, true, true),
('22222222-0000-0000-0000-000000000025', 'מורה להיסטוריה ואנגלית. בוגר אוניברסיטה העברית. מלמד בגישה דיאלוגית ומעמיקה.', 'טל אורן', 110, 55, 4.65, 6, 5, true, true);
